func siteIcon(
  _ icon: SiteIcon,
  class className: String,
  accessibilityLabel: String? = nil
) -> Node {
  var attributes = [
    "class": className,
    "fill": "none",
    "viewBox": icon.viewBox,
    "xmlns": "http://www.w3.org/2000/svg",
  ]

  if let accessibilityLabel {
    attributes["aria-label"] = accessibilityLabel
    attributes["role"] = "img"
  } else {
    attributes["aria-hidden"] = "true"
    attributes["focusable"] = "false"
  }

  return Node.element("svg", attributes, icon.contents)
}

private func svgPath(
  _ data: String,
  attributes: [String: String]
) -> Node {
  var attributes = attributes
  attributes["d"] = data.trimmingCharacters(in: .whitespacesAndNewlines)
  return Node.element("path", attributes, nil)
}
